const msg = $input.all()[0].json.message || $input.all()[0].json;
const text = (msg.text || '').trim();
const chatId = msg.chat ? msg.chat.id : '';

let komut = 'bilinmiyor';
let data = {};

if (text.startsWith('/ekle ')) {
  komut = 'ekle';
  const parts = text.replace('/ekle ', '').split(',');
  data = {
    markaAdi: (parts[0] || '').trim(),
    sektor: (parts[1] || 'Genel').trim(),
    rakipler: (parts[2] || '').trim().replace(/-/g, ', ')
  };
} else if (text.startsWith('/sil ')) {
  komut = 'sil';
  data = { markaAdi: text.replace('/sil ', '').trim() };
} else if (text === '/liste') {
  komut = 'liste';
} else if (text === '/analiz') {
  komut = 'analiz';
} else {
  komut = 'gecersiz';
}

return [{ json: { komut, chatId, ...data } }];

