const items = $input.all();
const chatId = $('Komutu Ayristir').first().json.chatId;
let mesaj = '📋 IZLENEN MARKALAR\n━━━━━━━━━━━━━━━━━━━━\n\n';
if (items.length === 0) {
  mesaj += 'Henuz marka eklenmemis. /ekle komutu ile ekleyin.';
} else {
  items.forEach((item, i) => {
    const d = item.json;
    mesaj += (i+1) + '. 🏢 ' + (d['Marka Adi'] || '') + '\n';
    mesaj += '   📊 ' + (d['Sektor'] || '') + '\n';
    mesaj += '   🏁 Rakipler: ' + (d['Rakipler'] || '-') + '\n\n';
  });
}
mesaj += '━━━━━━━━━━━━━━━━━━━━\nToplam: ' + items.length + ' marka';
return [{ json: { mesaj, chatId } }];

const items = $input.all();
return items.map(item => ({
  json: {
    markaAdi: item.json['Marka Adi'] || '',
    sektor: item.json['Sektor'] || '',
    rakipler: item.json['Rakipler'] || '',
    rssUrl: 'https://news.google.com/rss/search?q=' + encodeURIComponent(item.json['Marka Adi'] || '') + '&hl=tr&gl=TR&ceid=TR:tr'
  }
}));

const items = $input.all();
const markaBilgileri = $('RSS URL Hazirla').all();
const markaHaberleri = [];

for (let i = 0; i < items.length; i++) {
  const marka = markaBilgileri[i]?.json || {};
  const rawData = items[i].json;
  let xmlText = typeof rawData === 'string' ? rawData : (rawData.data || JSON.stringify(rawData));

  const haberler = [];
  const itemRegex = /<item>(.*?)<\/item>/gs;
  let match, count = 0;
  while ((match = itemRegex.exec(xmlText)) !== null && count < 5) {
    const titleMatch = match[1].match(/<title>(.*?)<\/title>/);
    const sourceMatch = match[1].match(/<source[^>]*>(.*?)<\/source>/);
    if (titleMatch) {
      haberler.push({ baslik: titleMatch[1].replace(/<[^>]*>/g, '').replace(/"/g, "'"), kaynak: sourceMatch ? sourceMatch[1].replace(/"/g, "'") : '' });
      count++;
    }
  }
  markaHaberleri.push({ marka: marka.markaAdi, sektor: marka.sektor, rakipler: marka.rakipler, haberler });
}

const bloklar = markaHaberleri.map(m => {
  const hList = m.haberler.length > 0 ? m.haberler.map((h, i) => (i+1) + '. ' + h.baslik + ' (' + h.kaynak + ')').join(', ') : 'Haber bulunamadi';
  return m.marka + ' (' + m.sektor + ') Rakipler: ' + m.rakipler + ' Haberler: ' + hList;
}).join(' ||| ');

const promptText = 'Sen profesyonel bir is istihbarat analistisin. Turkce yanit ver. ' + markaHaberleri.length + ' markayi analiz et: ' + bloklar + '. Her marka icin JSON dizisi dondur (SADECE JSON): [{marka, genel_duygu: pozitif/negatif/notr, duygu_puani: 1-10, risk_seviyesi: dusuk/orta/yuksek/kritik, ana_tema, onemli_gelismeler: [], riskler: [], firsatlar: [], rakip_karsilastirma, eylem_onerisi}]';

return [{ json: { promptText, markaHaberleri, toplamMarka: markaHaberleri.length } }];

function fixTR(t){if(!t)return '';return t.replace(/谋/g,'i').replace(/艧/g,'s').replace(/眉/g,'u').replace(/莽/g,'c').replace(/臒/g,'g').replace(/芒/g,'a').replace(/脺/g,'U').replace(/枚/g,'o');}
const gemini=$input.all()[0].json;
const tarih=new Date().toLocaleDateString('tr-TR');
const saat=new Date().toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'});
let analizler=[];
try{let m=fixTR(gemini.candidates[0].content.parts[0].text);const j=m.match(/\[\s*\{[\s\S]*\}\s*\]/);if(j)analizler=JSON.parse(j[0]);}catch(e){analizler=[{marka:'Hata',genel_duygu:'notr',duygu_puani:5,risk_seviyesi:'dusuk',ana_tema:'Analiz okunamadi',onemli_gelismeler:[],riskler:[],firsatlar:[],rakip_karsilastirma:'',eylem_onerisi:''}];}
return analizler.map(a=>({json:{tarih,saat,marka:fixTR(a.marka||''),genel_duygu:a.genel_duygu||'notr',duygu_puani:a.duygu_puani||5,risk_seviyesi:a.risk_seviyesi||'dusuk',ana_tema:fixTR(a.ana_tema||''),gelismeler:(a.onemli_gelismeler||[]).map(x=>fixTR(x)).join(' | '),riskler:(a.riskler||[]).map(x=>fixTR(x)).join(' | '),firsatlar:(a.firsatlar||[]).map(x=>fixTR(x)).join(' | '),rakip_notu:fixTR(a.rakip_karsilastirma||''),eylem:fixTR(a.eylem_onerisi||''),kritik_mi:(a.risk_seviyesi==='kritik'||a.risk_seviyesi==='yuksek')}}));

const items=$('Sonuc Ayristir').all();
const tarih=items[0]?.json.tarih||'';const saat=items[0]?.json.saat||'';
let mesaj='📊 ISTIHBARAT RAPORU\n📅 '+tarih+' '+saat+'\n━━━━━━━━━━━━━━━━━━━━\n\n';
items.forEach(item=>{
  const d=item.json;
  const emoji=d.genel_duygu==='pozitif'?'🟢':d.genel_duygu==='negatif'?'🔴':'🟡';
  mesaj+=emoji+' '+d.marka+' | Duygu: '+d.duygu_puani+'/10 | Risk: '+d.risk_seviyesi+'\n';
  mesaj+='   📌 '+d.ana_tema+'\n';
  if(d.gelismeler)mesaj+='   📰 '+d.gelismeler+'\n';
  mesaj+='\n';
});
mesaj+='━━━━━━━━━━━━━━━━━━━━\n'+items.length+' marka izlendi | 🤖 Gemini AI';
return [{json:{mesaj}}];
